CREATE TABLE IF NOT EXISTS app_users ( id BIGINT NOT NULL , email character varying(50) NOT NULL, first_name character varying(50) NOT NULL, last_name character varying(50) NOT NULL, phone character varying(30) NOT NULL, login character varying(50) NOT NULL, secret_word character varying(100) NOT NULL, s_cut character varying(20) NOT NULL, is_otp_required boolean DEFAULT true, user_avatar character varying(255) , user_image character varying(255) , partner_id varchar(50) , account_id varchar(50) , CONSTRAINT app_users_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS app_users_id_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY app_users.id;
